// Ang Yi Jie, Ivan, A0259256U
// Prioritise Files Node:
// Merges Person 2's output into a single prioritised list.
// Priority order:
//   1. rejected_missing_tests (0% coverage) — highest value
//   2. valid_files below 100% sorted by avgCoverage ascending
//
// Input (from Person 2 Rule based filter OR webhook body):
//   { valid_files: [{file, avgCoverage}], rejected_missing_tests: [string], removed_low_coverage: [...] }
//
// Config — edit these:
const GITHUB_OWNER = 'cs4218';
const GITHUB_REPO = 'cs4218-2520-ecom-project-cs4218-2520-team5';
const GITHUB_BRANCH = 'ivan1/ai-testing';
const MAX_FILES = 5;  // cap to avoid exceeding OpenAI token budget per run

let input;
if ($input.first().json.body) {
  // Came from Webhook node — body is nested under .body
  input = $input.first().json.body;
} else {
  // Came from Manual Trigger mock
  input = $input.first().json;
}

const missingTests = (input.rejected_missing_tests || []).map(file => ({
  file: typeof file === 'string' ? file : file.file,
  avgCoverage: 0,
  priority: 'missing',
}));

const validFiles = (input.valid_files || []).map(f => ({
  file: f.file,
  avgCoverage: f.avgCoverage,
  priority: 'low_coverage',
}));

// Sort low_coverage ascending (worst first)
validFiles.sort((a, b) => a.avgCoverage - b.avgCoverage);

// missing first, then low_coverage
const allFiles = [...missingTests, ...validFiles].slice(0, MAX_FILES);

if (allFiles.length === 0) {
  throw new Error('No files to generate tests for. Person 2 output had empty valid_files and rejected_missing_tests.');
}

return allFiles.map(f => ({
  json: {
    ...f,
    owner: GITHUB_OWNER,
    repo: GITHUB_REPO,
    branch: GITHUB_BRANCH,
    testOutputPath: 'tests/integration/' + f.file.split('/').pop().replace('.js', '') + '.ai-generated.test.js',
  }
}));

// Ang Yi Jie, Ivan, A0259256U
// Build Prompt Node (MS1): assemble the OpenAI chat prompt.
// Decodes the GitHub API base64 response and injects it into the prompt template.

const fileData = $input.first().json;
const loopItem = $('Loop Through Files').item.json;

// Decode base64 source file
let sourceCode;
try {
  sourceCode = Buffer.from(fileData.content, 'base64').toString('utf-8');
} catch (e) {
  throw new Error(`Failed to decode source for ${loopItem.file}: ${e.message}`);
}

const systemPrompt = `You are an expert software engineer writing Jest integration tests for a MERN stack e-commerce application (Virtual Vault).

Stack: Node.js, Express, Mongoose, MongoDB.
Test framework: Jest 29 with Babel (ESM via --experimental-vm-modules).
Integration test stack: MongoMemoryServer, Supertest, real Express routes, real Mongoose models.

Rules:
- Do NOT mock the controller or model layer under test.
- Only replace external dependencies: MongoDB → MongoMemoryServer, Braintree → jest.fn().
- Use ES module syntax (import/export). No require().
- Every test() must have at least one expect() assertion.
- Group tests in describe() blocks by function name.
- Start the file with exactly: // Ang Yi Jie, Ivan, A0259256U — AI-generated (MS1)
- Return ONLY the test file code inside a single \`\`\`javascript ... \`\`\` code block.`;

const userPrompt = `File to test: ${loopItem.file}
Current coverage: ${loopItem.avgCoverage}% (priority: ${loopItem.priority})

SOURCE CODE:
\`\`\`javascript
${sourceCode}
\`\`\`

Write complete Jest integration tests covering all exported functions.
For each controller function write at minimum:
  1. Happy path (valid inputs, expect 200/success)
  2. Missing required field (expect 400/error)
  3. Not found case where applicable (expect 404)

Use this setup pattern:
\`\`\`javascript
import { MongoMemoryServer } from 'mongodb-memory-server';
import mongoose from 'mongoose';
import request from 'supertest';
import jwt from 'jsonwebtoken';
import express from 'express';
// ... routes and models

let mongoServer, app;
beforeAll(async () => {
  process.env.JWT_SECRET = 'testsecret';
  mongoServer = await MongoMemoryServer.create();
  await mongoose.connect(mongoServer.getUri());
  app = express();
  app.use(express.json());
  app.use('/api/v1/...', routes);
});
afterAll(async () => { await mongoose.disconnect(); await mongoServer.stop(); });
aftereEach(async () => { await SomeModel.deleteMany({}); });
\`\`\`

Generate the complete test file now:`;

return [{
  json: {
    file: loopItem.file,
    avgCoverage: loopItem.avgCoverage,
    priority: loopItem.priority,
    owner: loopItem.owner,
    repo: loopItem.repo,
    branch: loopItem.branch,
    testOutputPath: loopItem.testOutputPath,
    sourceCode,
    systemPrompt,
    userPrompt,
  }
}];

// Ang Yi Jie, Ivan, A0259256U
// Format Test File — Code Node (MS1)
// Person 3's primary MS1 deliverable.
//
// Input: OpenAI chat completion response
// Output: { formattedTestFile, filename, sourceFile, linesOfCode, generatedAt }
//
// Steps:
//   1. Extract text from OpenAI response (choices[0].message.content)
//   2. Pull out the ```javascript ... ``` code block
//   3. Enforce author comment at top of file
//   4. Normalise line endings and strip trailing whitespace
//   5. Derive output filename

const response = $input.first().json;
const buildData = $('Build Prompt').item.json;

// Step 1: Extract content from OpenAI response
let rawText = '';
if (response.choices && Array.isArray(response.choices)) {
  rawText = response.choices[0]?.message?.content || '';
} else if (typeof response === 'string') {
  rawText = response;
}

if (!rawText) {
  throw new Error(`OpenAI returned empty content for ${buildData.file}. Check API key and prompt.`);
}

// Step 2: Extract code block  (```javascript ... ``` or ``` ... ```)
const codeBlockRegex = /```(?:javascript|js)?\n([\s\S]*?)```/;
const match = rawText.match(codeBlockRegex);
let testCode = match ? match[1].trim() : rawText.trim();

if (!testCode) {
  throw new Error('Could not extract code from OpenAI response.');
}

// Step 3: Enforce author comment
const authorLine = '// Ang Yi Jie, Ivan, A0259256U';
const generatedMarker = '— AI-generated (MS1)';

if (!testCode.startsWith('//')) {
  testCode = `${authorLine} ${generatedMarker}\n${testCode}`;
} else {
  const firstLineEnd = testCode.indexOf('\n');
  const firstLine = firstLineEnd === -1 ? testCode : testCode.slice(0, firstLineEnd);
  if (!firstLine.includes('A0259256U')) {
    testCode = `${authorLine} ${generatedMarker}\n` +
      (firstLineEnd === -1 ? '' : testCode.slice(firstLineEnd + 1));
  } else if (!firstLine.includes('AI-generated') && !firstLine.includes('Assisted with AI')) {
    testCode = `${firstLine} ${generatedMarker}\n` +
      (firstLineEnd === -1 ? '' : testCode.slice(firstLineEnd + 1));
  }
}

// Step 4: Normalise
testCode = testCode.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
testCode = testCode.split('\n').map(l => l.trimEnd()).join('\n');
testCode = testCode.replace(/\n+$/, '') + '\n';

// Step 5: Derive filename
const filename = buildData.testOutputPath;

return [{
  json: {
    formattedTestFile: testCode,
    filename,
    sourceFile: buildData.file,
    owner: buildData.owner,
    repo: buildData.repo,
    branch: buildData.branch,
    linesOfCode: testCode.split('\n').length,
    generatedAt: new Date().toISOString(),
  }
}];

// Ang Yi Jie, Ivan, A0259256U
// Build Edge Case Prompt (MS2)
// Takes the MS1 formatted test file and asks OpenAI to add edge cases.

const formatted = $input.first().json;

const systemPrompt = `You are an expert software engineer specialising in edge-case and boundary testing for Node.js/Express APIs.`;

const userPrompt = `You have been given a Jest test file. Add a new describe block with edge-case tests.

EXISTING TEST FILE:
\`\`\`javascript
${formatted.formattedTestFile}
\`\`\`

Add tests for:
1. BOUNDARY VALUES — empty string, null, undefined, 0, -1, very long strings for all fields.
2. MISSING REQUIRED FIELDS — one missing field at a time, expect 4xx.
3. INVALID TYPES — number where string expected, invalid ObjectId format.
4. AUTH EDGE CASES — no Authorization header (401), expired JWT (401), user token on admin route (401/403).
5. DUPLICATE HANDLING — create same resource twice, expect 400/409.

Rules:
- Only ADD a new describe block — do NOT rewrite existing tests.
- Every test() must have at least one expect().
- Use the same imports already in the file.
- Author comment for the new block: // Ang Yi Jie, Ivan, A0259256U — AI-generated edge cases (MS2)
- Return ONLY the new describe block inside a \`\`\`javascript ... \`\`\` block.`;

return [{
  json: {
    ...formatted,
    edgeSystemPrompt: systemPrompt,
    edgeUserPrompt: userPrompt,
  }
}];

// Ang Yi Jie, Ivan, A0259256U
// Merge Tests Node (MS2): append the edge-case describe block to the MS1 file.

const edgeResponse = $input.first().json;
const formatted = $('Build Edge Case Prompt').item.json;

// Extract edge-case code block from OpenAI response
let edgeRaw = edgeResponse.choices?.[0]?.message?.content || '';
const codeBlockRegex = /```(?:javascript|js)?\n([\s\S]*?)```/;
const match = edgeRaw.match(codeBlockRegex);
const edgeBlock = match ? match[1].trim() : edgeRaw.trim();

// Append to MS1 file (fall back gracefully if edge gen failed)
let merged;
if (edgeBlock) {
  merged = `${formatted.formattedTestFile}\n\n// --- MS2: Edge Cases & Boundary Tests (AI-generated) ---\n${edgeBlock}\n`;
} else {
  merged = formatted.formattedTestFile;
}

return [{
  json: {
    ...formatted,
    formattedTestFile: merged,
    linesOfCode: merged.split('\n').length,
    hasEdgeCases: !!edgeBlock,
  }
}];

// Ang Yi Jie, Ivan, A0259256U
// Validate Test Schema — Code Node (MS2)
// Person 3's primary MS2 deliverable.
//
// Schema rules:
//   Rule 1 — Jest format required: describe() + test()/it() + expect()
//   Rule 2 — No empty tests: every test body must have ≥1 expect()
//   Rule 3 — Valid imports only: known packages or relative paths; no require()

const ALLOWED_PACKAGES = new Set([
  'mongoose','express','jsonwebtoken','bcrypt','dotenv','slugify',
  'express-formidable','braintree','cors','morgan',
  'supertest','mongodb-memory-server','jest','@jest/globals',
  'babel-jest','@babel/core','@babel/preset-env','@babel/preset-react',
  'path','fs','crypto','util','os','http','https','stream','events',
  'buffer','url','assert','child_process',
]);

const item = $input.first().json;
const code = item.formattedTestFile;

if (!code || typeof code !== 'string') {
  return [{ json: { ...item, isValid: false, errors: ['formattedTestFile missing'], warnings: [], testCount: 0 } }];
}

const errors = [];
const warnings = [];

// Rule 1: Jest format
if (!/describe\s*\(/.test(code))
  errors.push('RULE1: No describe() block — Jest format required.');
if (!/(?:^|\s)(?:test|it)\s*\(/.test(code))
  errors.push('RULE1: No test() or it() block — Jest format required.');
if (!/expect\s*\(/.test(code))
  errors.push('RULE1: No expect() call — tests must have assertions.');

// Rule 2: No empty tests
const lines = code.split('\n');
let inTest = false, depth = 0, body = [], testCount = 0, emptyCount = 0, testName = '', startLine = 0;
for (let i = 0; i < lines.length; i++) {
  const ln = lines[i];
  if (!inTest) {
    const m = ln.match(/^\s*(?:test|it)\s*\(\s*(['"` + '`' + `])(.*?)\1/);
    if (m) { testCount++; inTest = true; depth = 0; body = []; testName = m[2]; startLine = i + 1; }
  }
  if (inTest) {
    for (const ch of ln) { if (ch==='{') depth++; if (ch==='}') { depth--; if(depth<0)depth=0; } }
    body.push(ln);
    if (/\{/.test(body.join('')) && depth === 0) {
      const full = body.join('\n');
      if (!/expect\s*\(|assert\s*\(/.test(full)) {
        emptyCount++;
        warnings.push(`RULE2: "${testName}" (line ${startLine}) has no assertions.`);
      }
      inTest = false; body = [];
    }
  }
}
if (emptyCount > 0)
  errors.push(`RULE2: ${emptyCount} test(s) have no assertions — no empty tests allowed.`);

// Rule 3: Valid imports
if (/\brequire\s*\(/.test(code))
  errors.push('RULE3: require() found — project uses ESM (import/export only).');
const importRe = /^import\s+.*?from\s+['"]([^'"]+)['"]/gm;
let m;
while ((m = importRe.exec(code)) !== null) {
  const pkg = m[1];
  if (pkg.startsWith('.') || pkg.startsWith('/') || pkg.startsWith('node:')) continue;
  const root = pkg.startsWith('@') ? pkg.split('/').slice(0,2).join('/') : pkg.split('/')[0];
  if (!ALLOWED_PACKAGES.has(root))
    warnings.push(`RULE3: Unknown import '${pkg}' — verify it exists in package.json.`);
}

// Quality checks
if (!code.includes('A0259256U'))
  warnings.push('QUALITY: Author comment missing or incomplete.');
if (testCount < 3)
  warnings.push(`QUALITY: Only ${testCount} test(s) — consider more coverage.`);

return [{ json: {
  ...item,
  isValid: errors.length === 0,
  errors,
  warnings,
  testCount,
  schemaCheckedAt: new Date().toISOString(),
} }];

// Prepare GitHub PUT payload: base64-encode the test file content.
const item = $input.first().json;
const content = Buffer.from(item.formattedTestFile).toString('base64');
return [{ json: {
  ...item,
  githubPutBody: {
    message: `test: AI-generated Jest tests for ${item.sourceFile} [Person 3 MS1+MS2]`,
    content,
    branch: item.branch,
  }
} }];
